CREATE TABLE IF NOT EXISTS classroomCourses (
  id INT AUTO_INCREMENT PRIMARY KEY,
  externalId VARCHAR(64) NOT NULL UNIQUE,
  name VARCHAR(256) NOT NULL,
  section VARCHAR(128),
  description TEXT,
  room VARCHAR(64),
  ownerName VARCHAR(128),
  enrollmentCode VARCHAR(32),
  courseState VARCHAR(32),
  alternateLink TEXT,
  subjectId INT,
  syncedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

ALTER TABLE classroomAssignments ADD COLUMN lifecycleStatus ENUM('to_do','in_progress','turned_in','graded') NOT NULL DEFAULT 'to_do';
ALTER TABLE classroomAssignments ADD COLUMN subjectId INT;
ALTER TABLE classroomAssignments ADD COLUMN startedAt TIMESTAMP NULL;
ALTER TABLE classroomAssignments ADD COLUMN turnedInAt TIMESTAMP NULL;
ALTER TABLE classroomAssignments ADD COLUMN gradedAt TIMESTAMP NULL;
ALTER TABLE classroomAssignments ADD COLUMN grade VARCHAR(32);
ALTER TABLE classroomAssignments ADD COLUMN gradeNumeric DECIMAL(6,2);
ALTER TABLE classroomAssignments ADD COLUMN driveFolderId VARCHAR(64);

CREATE TABLE IF NOT EXISTS classroomSubmissions (
  id INT AUTO_INCREMENT PRIMARY KEY,
  assignmentId INT NOT NULL,
  fromStatus ENUM('to_do','in_progress','turned_in','graded'),
  toStatus ENUM('to_do','in_progress','turned_in','graded') NOT NULL,
  changedBy VARCHAR(64),
  note TEXT,
  driveFileId VARCHAR(64),
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_assignment (assignmentId),
  INDEX idx_status (toStatus)
);

SELECT 'classroomCourses' AS tbl, COUNT(*) AS rows_present FROM classroomCourses
UNION ALL SELECT 'classroomAssignments', COUNT(*) FROM classroomAssignments
UNION ALL SELECT 'classroomSubmissions', COUNT(*) FROM classroomSubmissions;

